frappe.ui.form.on('HD Ticket', {
    remote_desktop: function(frm) {
        // جلب الـ IP من حقل ip_device
        var ip = frm.doc.ip_device;
        
        if (ip) {
            // فتح الرابط باستخدام البروتوكول rdp://
            window.location.href = 'rdp://' + ip;
            
            // إظهار تنبيه للمستخدم
            frappe.show_alert({
                message: __('Opening Remote Desktop for ' + ip),
                indicator: 'green'
            });
        } else {
            // رسالة في حال كان الحقل فارغاً
            frappe.msgprint(__('IP Device field is empty. Please ensure the IP is captured first.'));
        }
    }
});

frappe.ui.form.on('HD Ticket', {
    refresh: function (frm) {
        // Add custom behavior if needed
    },
    remote_desktop: function (frm) {
        if (frm.doc.ip_device) {
            // رابط التطبيق المحلي الخاص بك على البورت 8088
            const local_scanner_url = `http://localhost:8088/?ip=${frm.doc.ip_device}`;
            // فتح الرابط في نافذة جديدة
            window.open(local_scanner_url, '_blank');
            frappe.show_alert({
                message: __('جاري محاولة الاتصال بـ {0}...', [frm.doc.ip_device]),
                indicator: 'blue'
            });
        } else {
            frappe.msgprint(__('يرجى التأكد من وجود عنوان IP في حقل IP Device'));
        }
    }
});

