frappe.ui.form.on('Issue', {
    onload: function(frm) {
        // جلب اسم المستخدم الحالي
        if (!frm.doc.user_account) {
            frm.set_value('user_account', frappe.session.user);
        }

        // جلب اسم المرسل من DocType User
        frappe.db.get_value('User', frappe.session.user, 'full_name', (r) => {
            if (r && r.full_name) {
                frm.set_value('sender_name', r.full_name);
            }
        });

        // محاولة جلب اسم الجهاز و IP (يحتاج صلاحيات Client-side)
        frappe.call({
            method: "frappe.client.get_value",
            args: {
                doctype: "User",
                filters: { "name": frappe.session.user },
                fieldname: ["last_ip"]
            },
            callback: function(r) {
                if (r.message && r.message.last_ip) {
                    frm.set_value('device_ip', r.message.last_ip);
                }
            }
        });

        // جلب اسم الجهاز من الـ browser
        try {
            frm.set_value('device_name', window.navigator.userAgent);
        } catch (e) {
            console.log("Error fetching device name:", e);
        }

        // لا يمكن جلب MAC من المتصفح مباشرة (محظور أمنيًا)
        frm.set_df_property('device_mac', 'description', 'يتم تعبئتها يدويًا لأسباب أمان المتصفح');
    }
});

