frappe.ui.form.on('HD Ticket', {
    refresh: function(frm) {
       
        
        // Only show button if the document is saved (not new)
        if (!frm.is_new() && is_support) {
            
            // Add the button to the top right menu
            frm.add_custom_button(__('💻 Connect to Client'), function() {
                
                // 1. Fetch the Employee linked to the user who opened the issue (frm.doc.owner)
                frappe.db.get_value('user', { 'email': frm.doc.owner }, 'remote_id')
                    .then(r => {
                        let custom_rustdesk_id = r.message ? r.message.custom_rustdesk_id : null;

                        if (!custom_rustdesk_id) {
                            frappe.msgprint({
                                title: __('Remote ID Missing'),
                                indicator: 'red',
                                message: __('The employee who opened this issue (' + frm.doc.owner + ') does not have a Remote ID saved.')
                            });
                            return;
                        }

                        // 2. Define the fixed password
                        let password = "Awqaf1234Awqaf@@Awqaf";
                        
                        // 3. Construct the RustDesk URI scheme
                        let connectUrl = "rustdesk://" + custom_rustdesk_id;

                        // 4. Copy password to clipboard and launch
                        navigator.clipboard.writeText(password).then(function() {
                            frappe.show_alert({
                                message: __('Password copied! Opening RustDesk...'),
                                indicator: 'green'
                            }, 5); 
                            
                            // Launch RustDesk
                            window.location.href = connectUrl;
                            
                        }).catch(function(err) {
                            // Fallback: If clipboard fails, still try to open RustDesk
                            console.warn('Clipboard copy failed:', err);
                            frappe.show_alert({
                                message: __('Opening RustDesk (Password copy failed)...'),
                                indicator: 'orange'
                            });
                            window.location.href = connectUrl;
                        });
                    });
            }).addClass('btn-primary'); // Make the button blue
        }
    },

    custom_download_remote_software: function(frm) {
        // 1. Fetch Employee ID linked to the current user
        frappe.db.get_value('user', { 'email': frappe.session.user }, 'name')
            .then(r => {
                let employee_id = r.message ? r.message.name : null;

                if (!employee_id) {
                    frappe.msgprint({
                        title: __('Error'),
                        indicator: 'red',
                        message: __('Could not find an Employee ID linked to your account.')
                    });
                    return;
                }

                // 2. Generate the Batch File Content
                // Note: We use double backslashes \\ inside the JS string to ensure they appear as single \ in the file
                let bat_content = `
@echo off
setlocal EnableDelayedExpansion

:: --- CONFIGURATION VARIABLES ---
set "SERVER_IP=160.19.102.66"
set "DOWNLOAD_URL=https://system.moomken.org/files/rustdesk-1.4.5-x86_64.exe"

:: ERPNext API Details
