    powershell -Command "[Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12; Invoke-WebRequest -Uri '%DOWNLOAD_URL%' -OutFile '%~dp0%INSTALLER_NAME%'"
)

:: 2. Install
echo [2/6] Installing...
"%~dp0%INSTALLER_NAME%" --silent-install

:: 3. WAITING FOR FILE
echo [3/6] Waiting for installation to finish...
set "RUST_PATH="
for /L %%i in (1,1,20) do (
    if exist "C:\\Program Files\\RustDesk\\rustdesk.exe" set "RUST_PATH=C:\\Program Files\\RustDesk\\rustdesk.exe" & goto FOUND
    if exist "C:\\Program Files (x86)\\RustDesk\\rustdesk.exe" set "RUST_PATH=C:\\Program Files (x86)\\RustDesk\\rustdesk.exe" & goto FOUND
    timeout /t 2 /nobreak >nul
)

:FOUND
if "%RUST_PATH%"=="" (
    echo [ERROR] Installation timed out. rustdesk.exe not found.
    pause
    exit /b
)
echo Found RustDesk at: "%RUST_PATH%"

:: 4. Stop Service
echo [4/6] Configuring...
net stop rustdesk >nul 2>&1

:: 5. Write Config
set "PATH_SERVICE=C:\\Windows\\ServiceProfiles\\LocalService\\AppData\\Roaming\\RustDesk\\config"
