    powershell -Command "try { [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12; $res = Invoke-RestMethod -Uri '%ERP_URL%/api/resource/Employee/%TARGET_ID%' -Method Put -Headers @{ 'Authorization' = 'token %API_KEY%:%API_SECRET%' } -Body (@{ 'remote_id' = '!RUST_ID!' } | ConvertTo-Json) -ContentType 'application/json' -ErrorAction Stop; Write-Host 'SUCCESS: Record Updated.' -ForegroundColor Green } catch { Write-Host 'FAILURE: ' $_.Exception.Message -ForegroundColor Red }"
