                        print-color-adjust: exact !important;
                    }
                }
            `;

            let style = document.createElement('style');
            style.id = 'print-style-custom';
            style.innerHTML = css;
            document.head.appendChild(style);

            // 3. أمر الطباعة المباشر (يأخذ سكرين لما هو أمامك)
            setTimeout(function() {
                window.print();
            }, 500);
        });

        // تنسيق الزر
        $(btn).removeClass('btn-default').addClass('btn-primary').css("font-weight", "bold");
    }
};

