        if (frm.fields_dict.table_ujcq && frm.fields_dict.table_ujcq.wrapper) {
            // إزالة حواف الجدول الافتراضية ليتناسب مع التصميم الخاص بنا
            $(frm.fields_dict.table_ujcq.wrapper).find('.grid-wrapper').css({'border': 'none', 'border-radius': '0'});
            $(frm.fields_dict.table_ujcq.wrapper).appendTo(wrapper.$wrapper.find('#custom_table_wrapper'));
        }
    }, 100);

    bind_survey_events(frm, wrapper.$wrapper);
}

function bind_survey_events(frm, $wrapper) {
    const text_fields = [
        'full_name', 'phone', 'email', 'current_residence', 'city', 'project_location',
        'couples', 'grandchildren', 'boys_under_10', 'girls_under_10', 'boys_above_14', 'girls_above_14'
    ];
    
    text_fields.forEach(field => {
        $wrapper.find(`#ui_${field}`).on('change', function() {
            frm.set_value(field, $(this).val());
        });
    });

    $wrapper.find('#ui_special_needs_details').on('change', function() {
        frm.set_value('special_needs_details', $(this).val());
    });

    const select_fields = ['has_sketch', 'has_autocad', 'size_family', 'haya', 'travel'];
    
    select_fields.forEach(field => {
        $wrapper.find(`input[name="${field}"]`).on('change', function() {
            frm.set_value(field, $(this).val());
        });
    });

    // تفاعل حقل الاحتياجات الخاصة (تأثير الانزلاق اللطيف)
    $wrapper.find('input[name="has_special_needs"]').on('change', function() {
        let val = $(this).val();
        frm.set_value('has_special_needs', val);
        
        if (val === 'نعم') {
            $wrapper.find('#wrapper_special_needs_details').slideDown(250);
        } else {
            $wrapper.find('#wrapper_special_needs_details').slideUp(250);
            frm.set_value('special_needs_details', ''); 
            $wrapper.find('#ui_special_needs_details').val('');
        }
    });
}

