        if (frm.fields_dict.gg && frm.fields_dict.gg.wrapper) {
            $(frm.fields_dict.gg.wrapper).appendTo(wrapper.$wrapper.find('#custom_map_wrapper'));
        }
        if (frm.fields_dict.table_ujcq && frm.fields_dict.table_ujcq.wrapper) {
