frappe.ui.form.on('Building Survey', {

    refresh: function(frm) {
        toggle_relation_field(frm);
    },

    kitchen_type: function(frm) {
        toggle_relation_field(frm);
        suggest_relation(frm);
    },

    living_type: function(frm) {
        toggle_relation_field(frm);
        suggest_relation(frm);
    },

    dining_type: function(frm) {
        suggest_relation(frm);
    }
});


// 🎯 إظهار/إخفاء relation_type بشكل صحيح
function toggle_relation_field(frm) {

    let kitchen = frm.doc.kitchen_type;
    let living = frm.doc.living_type;

    // يظهر إذا أي واحد من الاثنين Open Space
    if (
        kitchen === "مطبخ مفتوح" ||
        living === "فراغ مفتوح"
    ) {
        frm.set_df_property("relation_type", "hidden", 0);
    } else {
        frm.set_df_property("relation_type", "hidden", 1);
        frm.set_value("relation_type", "");
    }
}


// 🤖 اقتراح العلاقات
function suggest_relation(frm) {

    let kitchen = frm.doc.kitchen_type;
    let living = frm.doc.living_type;
    let dining = frm.doc.dining_type;

    // 🔥 كامل Open Space
    if (
        kitchen === "مطبخ مفتوح" &&
        living === "فراغ مفتوح" &&
        dining === "فراغ مفتوح"
    ) {
        frm.set_value("relation_type", "المعيشة مفتوحة على المطبخ والأكل");
        return;
    }

    // 🔥 معيشة + أكل
    if (
        living === "فراغ مفتوح" &&
        dining === "فراغ مفتوح"
    ) {
        frm.set_value("relation_type", "المعيشة مفتوحة على الأكل");
        return;
    }

    // 🔥 مطبخ + معيشة
    if (
        kitchen === "مطبخ مفتوح" &&
        living === "فراغ مفتوح"
    ) {
        frm.set_value("relation_type", "مطبخ مفتوح على المعيشة");
        return;
    }

    // 🔥 مطبخ + أكل
    if (
        kitchen === "مطبخ مفتوح" &&
        dining === "فراغ مفتوح"
    ) {
        frm.set_value("relation_type", "مطبخ مفتوح على الأكل");
        return;
    }
}
